import { useSearchParams } from 'next/navigation'
import { Suspense } from 'react'

function LicenseErrorContent() {
  const params   = useSearchParams()
  const reason   = params.get('reason')
  const expected = params.get('expected')

  const isDomainError = reason === 'domain'

  return (
    <div style={{
      display:        'flex',
      flexDirection:  'column',
      alignItems:     'center',
      justifyContent: 'center',
      minHeight:      '100vh',
      background:     '#0f172a',
      color:          '#f1f5f9',
      fontFamily:     '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
      textAlign:      'center',
      padding:        '32px',
    }}>

      {/* Icon */}
      <div style={{ fontSize: 72, marginBottom: 8 }}>🔒</div>

      {/* Title */}
      <h1 style={{
        fontSize:   32,
        fontWeight: 700,
        margin:     '16px 0 8px',
        color:      '#f1f5f9',
      }}>
        License Error
      </h1>

      {/* Subtitle */}
      <p style={{
        fontSize:   16,
        color:      '#94a3b8',
        maxWidth:   440,
        lineHeight: 1.7,
        margin:     '0 0 32px',
      }}>
        {isDomainError
          ? 'This server is not authorized to run EduDesk. The domain does not match the issued license.'
          : 'There is a problem with your EduDesk license. Please contact CloudTitans support.'}
      </p>

      {/* Detail card */}
      <div style={{
        background:   '#1e293b',
        border:       '1px solid #334155',
        borderRadius: 12,
        padding:      '28px 36px',
        maxWidth:     440,
        width:        '100%',
        marginBottom: 32,
        textAlign:    'left',
      }}>
        {isDomainError && expected && (
          <div style={{
            background:   '#0f172a',
            border:       '1px solid #334155',
            borderRadius: 8,
            padding:      '12px 16px',
            marginBottom: 20,
            fontFamily:   'monospace',
            fontSize:     13,
          }}>
            <span style={{ color: '#64748b' }}>License domain: </span>
            <span style={{ color: '#f59e0b' }}>{expected}</span>
          </div>
        )}

        <p style={{ color: '#94a3b8', fontSize: 14, margin: '0 0 8px' }}>
          Possible causes:
        </p>
        <ul style={{ color: '#64748b', fontSize: 14, paddingLeft: 20, lineHeight: 2, margin: '0 0 20px' }}>
          <li>APP_DOMAIN in .env does not match the license</li>
          <li>The LICENSE.key file is missing or corrupted</li>
          <li>The 30-day setup window for edudesk.local has expired</li>
        </ul>

        <a
          href="mailto:support@ctitans.com?subject=EduDesk License Error"
          style={{
            display:        'block',
            padding:        '12px 28px',
            background:     '#2563eb',
            color:          '#fff',
            borderRadius:   8,
            textDecoration: 'none',
            fontWeight:     600,
            fontSize:       15,
            textAlign:      'center',
          }}
        >
          📧 Contact CloudTitans Support
        </a>
      </div>

      {/* Footer */}
      <p style={{ color: '#334155', fontSize: 13 }}>
        Powered by CloudTitans © 2026 · EduDesk v3.0
      </p>
    </div>
  )
}

export default function LicenseErrorPage() {
  return (
    <Suspense fallback={null}>
      <LicenseErrorContent />
    </Suspense>
  )
}
